defmodule MyAppWeb.UserController do
  use MyAppWeb, :controller
  
  alias MyApp.Accounts
  alias MyApp.Accounts.User
  alias MyApp.Repo
  
  action_fallback MyAppWeb.FallbackController

  def update(conn, %{"id" => id} = params) do
    current_user = conn.assigns.current_user
    
    with {:ok, user} <- get_user(id),
         :ok <- authorize_resource_access(current_user, user),
         :ok <- authorize_tenant_access(current_user, user),
         :ok <- authorize_role_update(current_user, user, params),
         filtered_params <- filter_updatable_fields(current_user, user, params),
         changeset <- User.changeset(user, filtered_params),
         {:ok, updated_user} <- Repo.update(changeset) do
      conn
      |> put_status(:ok)
      |> render("user.json", user: updated_user)
    else
      {:error, :not_found} ->
        conn
        |> put_status(:not_found)
        |> json(%{error: "User not found"})
      
      {:error, :unauthorized} ->
        conn
        |> put_status(:forbidden)
        |> json(%{error: "Unauthorized to perform this action"})
      
      {:error, :tenant_mismatch} ->
        conn
        |> put_status(:forbidden)
        |> json(%{error: "Cannot access user from different tenant"})
      
      {:error, :role_unauthorized} ->
        conn
        |> put_status(:forbidden)
        |> json(%{error: "Insufficient permissions to update user role"})
      
      {:error, %Ecto.Changeset{} = changeset} ->
        conn
        |> put_status(:unprocessable_entity)
        |> render("error.json", changeset: changeset)
    end
  end

  defp get_user(id) do
    case Repo.get(User, id) do
      nil -> {:error, :not_found}
      user -> {:ok, user}
    end
  end

  defp authorize_resource_access(current_user, target_user) do
    cond do
      current_user.id == target_user.id ->
        :ok
      
      has_role?(current_user, [:admin, :super_admin]) ->
        :ok
      
      has_role?(current_user, :manager) && can_manage?(current_user, target_user) ->
        :ok
      
      true ->
        {:error, :unauthorized}
    end
  end

  defp authorize_tenant_access(current_user, target_user) do
    cond do
      has_role?(current_user, :super_admin) ->
        :ok
      
      current_user.tenant_id == target_user.tenant_id ->
        :ok
      
      true ->
        {:error, :tenant_mismatch}
    end
  end

  defp authorize_role_update(current_user, target_user, params) do
    cond do
      not Map.has_key?(params, "role") && not Map.has_key?(params, :role) ->
        :ok
      
      has_role?(current_user, :super_admin) ->
        :ok
      
      has_role?(current_user, :admin) && can_assign_role?(current_user, params) ->
        :ok
      
      true ->
        {:error, :role_unauthorized}
    end
  end

  defp filter_updatable_fields(current_user, target_user, params) do
    base_fields = [:email, :name, :phone, :address, :bio, :avatar_url]
    
    allowed_fields = cond do
      has_role?(current_user, :super_admin) ->
        [:email, :name, :phone, :address, :bio, :avatar_url, :role, :tenant_id, 
         :status, :permissions, :metadata, :verified, :active]
      
      has_role?(current_user, :admin) ->
        [:email, :name, :phone, :address, :bio, :avatar_url, :role, :status, 
         :permissions, :verified, :active]
      
      has_role?(current_user, :manager) ->
        [:email, :name, :phone, :address, :bio, :status, :active]
      
      current_user.id == target_user.id ->
        base_fields
      
      true ->
        []
    end
    
    params
    |> Enum.filter(fn {key, _value} ->
      field = if is_binary(key), do: String.to_existing_atom(key), else: key
      field in allowed_fields
    rescue
      ArgumentError -> false
    end)
    |> Enum.into(%{})
  end

  defp has_role?(user, roles) when is_list(roles) do
    Enum.any?(roles, fn role -> has_role?(user, role) end)
  end

  defp has_role?(user, role) when is_atom(role) do
    user.role == role || user.role == to_string(role)
  end

  defp can_manage?(manager, target_user) do
    manager.tenant_id == target_user.tenant_id &&
      target_user.manager_id == manager.id &&
      !has_role?(target_user, [:admin, :super_admin, :manager])
  end

  defp can_assign_role?(admin, params) do
    new_role = params["role"] || params[:role]
    restricted_roles = ["super_admin", :super_admin]
    
    new_role not in restricted_roles
  end
end

defmodule MyApp.Accounts.User do
  use Ecto.Schema
  import Ecto.Changeset

  schema "users" do
    field :email, :string
    field :name, :string
    field :phone, :string
    field :address, :string
    field :bio, :string
    field :avatar_url, :string
    field :role, :string
    field :tenant_id, :integer
    field :manager_id, :integer
    field :status, :string
    field :permissions, {:array, :string}
    field :metadata, :map
    field :verified, :boolean
    field :active, :boolean
    field :password_hash, :string

    timestamps()
  end

  def changeset(user, attrs) do
    user
    |> cast(attrs, [
      :email, :name, :phone, :address, :bio, :avatar_url, :role, 
      :tenant_id, :manager_id, :status, :permissions, :metadata, 
      :verified, :active, :password_hash
    ])
    |> validate_required([:email])
    |> validate_format(:email, ~r/@/)
    |> validate_inclusion(:role, ["user", "manager", "admin", "super_admin"])
    |> validate_inclusion(:status, ["active", "inactive", "suspended", "pending"])
    |> unique_constraint(:email)
  end
end